public class Main {
    /**
     * 反射打印一个类的所有声明字段与 @SerializedName, 便于核对真实 schema *
     */
    private static void dumpDeclaredFields(String label, Class<?> clz) { 
        System.out.println("-- " + label + " (" + clz.getName() + ") --");
        for (Field f : clz.getDeclaredFields()) {
            com.google.gson.annotations.Deserialize sn =
                f.getAnnotation(com.google.gson.annotations.Deserialize.class);
            String json = sn != null ? sn.value() : f.getName();
            System.out.printf("    %-32s java:%-18s -> %s%n",
                "@SerializedName(\"" + json + "\")", f.getName(), f.getType().getSimpleName());
        }
    }
}
```

